eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   scienceTopicOrder: () => (/* binding */ scienceTopicOrder),\n/* harmony export */   scienceTopics: () => (/* binding */ scienceTopics)\n/* harmony export */ });\nconst scienceTopicOrder = [\n    \"reincarnation\",\n    \"quantum\",\n    \"sovereignty\"\n];\nconst scienceTopics = {\n    reincarnation: {\n        en: {\n            title: \"Reincarnation & Afterlife Research\",\n            tagline: \"Empirical patterns beyond one lifetime\",\n            intro: \"Alethemora treats reincarnation and afterlife research as a disciplined evidence field, not a belief badge. The focus is pattern consistency, cross-source convergence, and practical implications for ethical living.\",\n            sections: [\n                {\n                    heading: \"Research Lineage\",\n                    paragraphs: [\n                        \"Michael Newton documented highly consistent structures in thousands of deep-regression sessions: soul groups, life planning, guides, life review, and developmental stages.\",\n                        \"Ian Stevenson and Jim Tucker added a complementary evidentiary layer through child cases with verifiable memories, behavioral correspondences, and birthmark/injury parallels in selected datasets.\"\n                    ],\n                    bullets: [\n                        \"Convergence across independent methods matters more than isolated anecdotes.\",\n                        \"Alethemora uses these findings as working models, not as infallible doctrine.\"\n                    ]\n                },\n                {\n                    heading: \"Near-Death Convergence\",\n                    paragraphs: [\n                        \"Near-death studies provide a second line of evidence: stable motifs such as expanded awareness, panoramic review, non-local perception, and enduring value shifts after return.\",\n                        \"For practice, this reframes death from annihilation panic toward continuity-responsibility: how one lives now shapes experiential quality later.\"\n                    ]\n                },\n                {\n                    heading: \"Practical Consequence\",\n                    paragraphs: [\n                        \"If consciousness continues, integrity is not moral theater; it is energetic realism. Harm, deception, and denial remain unresolved loads in the field of the self.\",\n                        \"Therefore daily reflection, forgiveness, and corrective action are intelligent preparation, not religious guilt-management.\"\n                    ]\n                }\n            ]\n        },\n        de: {\n            title: \"Reinkarnation & Jenseitsforschung\",\n            tagline: \"Empirische Muster jenseits einer Lebensspanne\",\n            intro: \"Alethemora behandelt Reinkarnations- und Jenseitsforschung als diszipliniertes Evidenzfeld, nicht als Glaubensabzeichen. Im Fokus stehen Musterkonsistenz, Quellenkonvergenz und praktische Konsequenzen f\\xfcr ein integres Leben.\",\n            sections: [\n                {\n                    heading: \"Forschungslinie\",\n                    paragraphs: [\n                        \"Michael Newton dokumentierte in tausenden Tiefenregressionen hochkonsistente Strukturen: Seelengruppen, Lebensplanung, Geistf\\xfchrer, Life Review und Reifestufen.\",\n                        \"Ian Stevenson und Jim Tucker erg\\xe4nzten eine zweite Evidenzschicht \\xfcber Kindheitsf\\xe4lle mit \\xfcberpr\\xfcfbaren Erinnerungen, Verhaltenskorrespondenzen und in ausgew\\xe4hlten Datens\\xe4tzen passenden Geburtsmal-/Verletzungsmustern.\"\n                    ],\n                    bullets: [\n                        \"Konvergenz \\xfcber unabh\\xe4ngige Methoden ist wichtiger als Einzelanekdoten.\",\n                        \"Alethemora nutzt diese Befunde als Arbeitsmodelle, nicht als unfehlbares Dogma.\"\n                    ]\n                },\n                {\n                    heading: \"Konvergenz mit Nahtoderfahrung\",\n                    paragraphs: [\n                        \"Nahtoderfahrungsforschung liefert eine zweite Linie: stabile Motive wie erweiterte Wahrnehmung, panoramischer R\\xfcckblick, nicht-lokale Bewusstheit und dauerhafte Wertverschiebungen nach R\\xfcckkehr.\",\n                        \"F\\xfcr die Praxis bedeutet das: Tod wird weniger als Ausl\\xf6schung und mehr als Kontinuit\\xe4t mit Verantwortung verstanden.\"\n                    ]\n                },\n                {\n                    heading: \"Praktische Konsequenz\",\n                    paragraphs: [\n                        \"Wenn Bewusstsein fortbesteht, ist Integrit\\xe4t keine Moralinszenierung, sondern energetischer Realismus. Schaden, T\\xe4uschung und Verdr\\xe4ngung bleiben als ungel\\xf6ste Last im Feld des Selbst.\",\n                        \"Darum sind t\\xe4gliche Reflexion, Vergebung und Korrekturakte intelligente Vorbereitung, nicht religi\\xf6ses Schulddenken.\"\n                    ]\n                }\n            ]\n        }\n    },\n    quantum: {\n        en: {\n            title: \"Quantum Physics & Resonance\",\n            tagline: \"From mechanism to participatory reality\",\n            intro: \"Alethemora does not misuse physics as mystic decoration. It draws a careful bridge: modern physics destabilizes naive materialism and opens conceptual space for non-local, relational models of consciousness.\",\n            sections: [\n                {\n                    heading: \"Non-Locality & Relational Structure\",\n                    paragraphs: [\n                        \"Quantum non-local correlations challenge strictly separative worldviews. At minimum, they force humility about what 'independent objects' means at fundamental levels.\",\n                        \"In practice language, this supports a resonance paradigm: inner state and outer expression are not isolated events but coupled dynamics in a shared field.\"\n                    ]\n                },\n                {\n                    heading: \"Observer and Measurement\",\n                    paragraphs: [\n                        \"Interpretations differ, but one insight remains: observation and measured reality cannot be treated as fully detached in every framework.\",\n                        \"Alethemora translates this philosophically: attention quality matters. What is repeatedly attended, emotionally charged, and enacted tends to stabilize as lived reality.\"\n                    ],\n                    bullets: [\n                        \"Attention is not magic; it is directional energy with cumulative effects.\",\n                        \"Discipline of perception precedes discipline of action.\"\n                    ]\n                },\n                {\n                    heading: \"Resonance Ethics\",\n                    paragraphs: [\n                        \"Resonance means coherence between thought, feeling, speech, and action. Dissonance means fragmentation across these layers.\",\n                        \"Hence the framework is causal, not moralistic: coherent patterns increase clarity and vitality; incoherent patterns increase noise and suffering.\"\n                    ]\n                }\n            ]\n        },\n        de: {\n            title: \"Quantenphysik & Resonanz\",\n            tagline: \"Vom Mechanismus zur teilnehmenden Wirklichkeit\",\n            intro: \"Alethemora missbraucht Physik nicht als spirituelle Dekoration. Es baut eine pr\\xe4zise Br\\xfccke: Moderne Physik ersch\\xfcttert naiven Materialismus und \\xf6ffnet einen Denkraum f\\xfcr nicht-lokale, relationale Bewusstseinsmodelle.\",\n            sections: [\n                {\n                    heading: \"Nichtlokalit\\xe4t & relationale Struktur\",\n                    paragraphs: [\n                        \"Quantenkorrelationen stellen strikt trennende Weltbilder infrage. Mindestens erzwingen sie epistemische Demut dar\\xfcber, was auf fundamentaler Ebene als 'unabh\\xe4ngiges Objekt' gilt.\",\n                        \"In Praxissprache st\\xfctzt das ein Resonanzmodell: innerer Zustand und \\xe4u\\xdferer Ausdruck sind keine isolierten Ereignisse, sondern gekoppelte Dynamiken im gemeinsamen Feld.\"\n                    ]\n                },\n                {\n                    heading: \"Beobachter und Messung\",\n                    paragraphs: [\n                        \"Interpretationen unterscheiden sich, doch eine Einsicht bleibt: Beobachtung und gemessene Wirklichkeit lassen sich nicht in jedem Rahmen vollst\\xe4ndig trennen.\",\n                        \"Alethemora \\xfcbersetzt das philosophisch: Die Qualit\\xe4t von Aufmerksamkeit ist relevant. Was wiederholt fokussiert, emotional aufgeladen und gehandelt wird, stabilisiert sich als gelebte Realit\\xe4t.\"\n                    ],\n                    bullets: [\n                        \"Aufmerksamkeit ist keine Magie, sondern gerichtete Energie mit Kumulationseffekt.\",\n                        \"Disziplin der Wahrnehmung geht Disziplin des Handelns voraus.\"\n                    ]\n                },\n                {\n                    heading: \"Resonanz-Ethik\",\n                    paragraphs: [\n                        \"Resonanz bedeutet Koh\\xe4renz zwischen Denken, F\\xfchlen, Sprechen und Handeln. Dissonanz bedeutet Fragmentierung zwischen diesen Ebenen.\",\n                        \"Darum ist der Ansatz kausal statt moralistisch: koh\\xe4rente Muster erh\\xf6hen Klarheit und Vitalit\\xe4t, inkoh\\xe4rente Muster erh\\xf6hen Rauschen und Leiden.\"\n                    ]\n                }\n            ]\n        }\n    },\n    sovereignty: {\n        en: {\n            title: \"Decentralized Sovereignty & Bitcoin\",\n            tagline: \"Economic freedom as spiritual infrastructure\",\n            intro: \"Alethemora treats economics as applied ethics. If soul growth requires responsibility, then monetary architecture must reward honesty, time preference discipline, and voluntary coordination.\",\n            sections: [\n                {\n                    heading: \"Austrian Foundation\",\n                    paragraphs: [\n                        \"In Austrian economics, capital is condensed time, effort, and risk. Distorting money distorts human coordination itself.\",\n                        \"Inflationary and centrally manipulated systems externalize costs to the less connected while rewarding proximity to issuance and leverage.\"\n                    ],\n                    bullets: [\n                        \"Money is not neutral plumbing; it is civilizational signal structure.\",\n                        \"Bad incentives produce moral and psychological downstream effects.\"\n                    ]\n                },\n                {\n                    heading: \"Bitcoin as Monetary Rule-Set\",\n                    paragraphs: [\n                        \"Bitcoin introduces a transparent, finite, non-discretionary rule set. In Alethemora terms, it can be viewed as 'frozen life energy': saved effort protected from arbitrary dilution.\",\n                        \"This is why it maps to sovereignty: it reduces dependence on central decree and restores long-horizon planning for individuals and communities.\"\n                    ]\n                },\n                {\n                    heading: \"Bridge to Soul Mastery\",\n                    paragraphs: [\n                        \"Spiritual work without material sovereignty remains structurally vulnerable. Constant extraction pressure narrows cognition toward survival loops.\",\n                        \"A freer monetary substrate supports dignity, voluntary cooperation, and the time-depth required for real inner development.\"\n                    ]\n                }\n            ]\n        },\n        de: {\n            title: \"Dezentrale Souver\\xe4nit\\xe4t & Bitcoin\",\n            tagline: \"\\xd6konomische Freiheit als spirituelle Infrastruktur\",\n            intro: \"Alethemora versteht \\xd6konomie als angewandte Ethik. Wenn Seelenwachstum Verantwortung braucht, muss auch die monet\\xe4re Architektur Ehrlichkeit, Zeitpr\\xe4ferenz-Disziplin und freiwillige Koordination belohnen.\",\n            sections: [\n                {\n                    heading: \"\\xd6sterreichisches Fundament\",\n                    paragraphs: [\n                        \"In der \\xd6sterreichischen Schule ist Kapital verdichtete Zeit, Anstrengung und Risiko. Wer Geld verzerrt, verzerrt menschliche Koordination selbst.\",\n                        \"Inflation\\xe4re und zentral manipulierbare Systeme externalisieren Kosten auf weniger Verbundene und belohnen N\\xe4he zu Emission und Leverage.\"\n                    ],\n                    bullets: [\n                        \"Geld ist nicht neutrale Infrastruktur, sondern zivilisatorische Signalstruktur.\",\n                        \"Schlechte Anreize erzeugen moralische und psychologische Folgewirkungen.\"\n                    ]\n                },\n                {\n                    heading: \"Bitcoin als monet\\xe4res Regelwerk\",\n                    paragraphs: [\n                        \"Bitcoin etabliert ein transparentes, endliches, nicht-diskretion\\xe4res Regelwerk. In Alethemora-Sprache kann es als 'gefrorene Lebensenergie' gelesen werden: gespeicherte Leistung, gesch\\xfctzt vor willk\\xfcrlicher Verw\\xe4sserung.\",\n                        \"Darum korrespondiert Bitcoin mit Souver\\xe4nit\\xe4t: Abh\\xe4ngigkeit von zentralem Dekret sinkt, langfristige Planung f\\xfcr Individuen und Gemeinschaften steigt.\"\n                    ]\n                },\n                {\n                    heading: \"Br\\xfccke zur Seelenmeisterschaft\",\n                    paragraphs: [\n                        \"Spirituelle Arbeit ohne materielle Souver\\xe4nit\\xe4t bleibt strukturell verletzlich. Permanenter Extraktionsdruck verengt Kognition auf \\xdcberlebensschleifen.\",\n                        \"Ein freieres monet\\xe4res Substrat unterst\\xfctzt W\\xfcrde, freiwillige Kooperation und die zeitliche Tiefe, die echte innere Entwicklung ben\\xf6tigt.\"\n                    ]\n                }\n            ]\n        }\n    }\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/science-hub.ts\n");

